struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket packet;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read packet_id
    packet.packet_id = stream.get<uint32_t>();

    // Read username with length prefix
    packet.username = stream.get<std::string>(hexi::prefixed{});

    // Read score count and then the scores vector
    uint32_t score_count = stream.get<uint32_t>();
    packet.scores = stream.get<std::vector<uint32_t>>(hexi::count(score_count));

    // Read metadata as null-terminated string
    packet.metadata = stream.get<std::string>(hexi::null_terminated{});

    // Skip any remaining padding bytes
    if (stream.position() < adaptor.size()) {
        stream.skip(adaptor.size() - stream.position());
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use span() for zero-copy view of packet_id
    auto packet_id_span = stream.span<uint32_t>(1);
    info.packet_id = packet_id_span[0];

    // Read username using prefixed adaptor for string_view
    info.username = stream.get<std::string_view>(hexi::prefixed{});

    // Skip scores vector: read count then skip the data
    uint32_t score_count = stream.get<uint32_t>();
    stream.skip(score_count * sizeof(uint32_t));

    return info;
