```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create buffer adaptor for the target buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream with no-throw error handling
    hexi::binary_stream stream(adaptor, hexi::no_throw);

    // Check available space before writing
    // We need space for: header (uint32_t) + vector size (varint) + all items (uint32_t each)
    size_t required_space = sizeof(header) + stream.varint_size(items.size()) + items.size() * sizeof(uint32_t);

    if (adaptor.write_size() < required_space) {
        return false; // Insufficient space
    }

    // Write the header
    stream.put(header);

    // Write the vector of items using write_container
    stream.write_container(items);

    // Check if write was successful by verifying stream state
    return static_cast<bool>(stream);
}
```

