#include "implementation.hpp"

// Helper function to create test buffer
std::vector<uint8_t> create_header_buffer(uint32_t magic, uint16_t version, uint16_t flags) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream << magic << version << flags;
    return buffer;
}

TEST(BufferReadSpan, ReadHeader) {
    auto buffer = create_header_buffer(0x12345678, 1, 0x42);

    PacketHeader header = read_header_with_span(buffer);

    EXPECT_EQ(0x12345678, header.magic);
    EXPECT_EQ(1, header.version);
    EXPECT_EQ(0x42, header.flags);
}

TEST(BufferReadSpan, ReadDifferentValues) {
    auto buffer = create_header_buffer(0xABCDEF00, 2, 0xFF);

    PacketHeader header = read_header_with_span(buffer);

    EXPECT_EQ(0xABCDEF00, header.magic);
    EXPECT_EQ(2, header.version);
    EXPECT_EQ(0xFF, header.flags);
}

TEST(BufferReadSpan, InsufficientData) {
    std::vector<uint8_t> buffer = {1, 2, 3};

    PacketHeader header = read_header_with_span(buffer);

    EXPECT_EQ(0, header.magic);
    EXPECT_EQ(0, header.version);
    EXPECT_EQ(0, header.flags);
}

