```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <stdexcept>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor from the span
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream with the adaptor
    hexi::binary_stream stream(adaptor);

    // Check if there's enough data available for the header
    constexpr size_t header_size = sizeof(uint32_t) + sizeof(uint16_t) + sizeof(uint16_t);
    if (adaptor.available() < header_size) {
        throw std::runtime_error("Insufficient data for header");
    }

    // Get the read pointer from buffer adaptor
    const std::byte* read_ptr = adaptor.read_ptr();

    // Create a zero-copy view of the header using the read pointer
    // Cast to const uint8_t* for span construction
    const uint8_t* header_data = reinterpret_cast<const uint8_t*>(read_ptr);
    std::span<const uint8_t> header_span(header_data, header_size);

    // Use binary_stream to read the header data with zero-copy operations
    PacketHeader header;

    // Read magic number (uint32_t)
    auto magic_span = header_span.subspan(0, sizeof(uint32_t));
    header.magic = stream.get<uint32_t>();

    // Read version (uint16_t)  
    auto version_span = header_span.subspan(sizeof(uint32_t), sizeof(uint16_t));
    header.version = stream.get<uint16_t>();

    // Read flags (uint16_t)
    auto flags_span = header_span.subspan(sizeof(uint32_t) + sizeof(uint16_t), sizeof(uint16_t));
    header.flags = stream.get<uint16_t>();

    return header;
}
```

