    for (size_t i = 0; i < bytes_to_peek; ++i) {
        try {
            // Use the buffer's operator[] to access data at the current read position + offset
            // This assumes the buffer provides random access to its data
            auto byte = buffer[current_read_pos + i];
            result.push_back(static_cast<uint8_t>(byte));
        } catch (const std::out_of_range&) {
            // If we try to read beyond available data, break early
            break;
        }
    }

    return result;
}

