    uint32_t* mixed_ptr3 = allocator.allocate();

    std::cout << "Re-allocated 3 blocks:\n";
    std::cout << "  Block 1: " << static_cast<void*>(mixed_ptr1) << "\n";
    std::cout << "  Block 2: " << static_cast<void*>(mixed_ptr2) << "\n";  
    std::cout << "  Block 3: " << static_cast<void*>(mixed_ptr3) << "\n";

    // Due to LIFO, we expect the allocation order to match reverse deallocation order
    // (last deallocated should be first allocated)
    assert(mixed_ptr1 == reallocated_ptrs[7] && "Expected LIFO behavior");
    assert(mixed_ptr2 == reallocated_ptrs[5] && "Expected LIFO behavior"); 
    assert(mixed_ptr3 == reallocated_ptrs[2] && "Expected LIFO behavior");

    // Clean up remaining allocations
    for (size_t i = 0; i < element_count; ++i) {
        if (i != 2 && i != 5 && i != 7) { // Skip already deallocated ones
            allocator.deallocate(reallocated_ptrs[i]);
        }
    }
    allocator.deallocate(mixed_ptr1);
    allocator.deallocate(mixed_ptr2);
    allocator.deallocate(mixed_ptr3);

    std::cout << "\n=== Demonstration Complete ===\n";
    std::cout << "The behavior demonstrates that block_allocator uses a LIFO free list:\n";
    std::cout << "- Deallocated blocks are 'pushed' onto the free list head\n";
    std::cout << "- Allocated blocks are 'popped' from the free list head\n";
    std::cout << "- This results in Last-In-First-Out (LIFO) behavior\n";
}

