#include <gtest/gtest.h>
#include <hexi/static_buffer.h>
#include <cstdint>
#include <vector>

// Include the implementation
#include "implementation.hpp"

TEST(StaticBuffer, GetReadPointer) {
    hexi::static_buffer<std::byte, 1024> buffer;
    std::vector<uint8_t> test_data = {1, 2, 3, 4, 5};
    buffer.write(test_data.data(), test_data.size());

    const std::byte* read_ptr = get_read_pointer(buffer);

    ASSERT_NE(nullptr, read_ptr);
    EXPECT_EQ(1, static_cast<uint8_t>(read_ptr[0]));
    EXPECT_EQ(2, static_cast<uint8_t>(read_ptr[1]));
}

TEST(StaticBuffer, GetWritePointer) {
    hexi::static_buffer<std::byte, 1024> buffer;

    std::byte* write_ptr = get_write_pointer(buffer);

    ASSERT_NE(nullptr, write_ptr);

    // Write data directly using the pointer
    uint8_t test_value = 42;
    std::memcpy(write_ptr, &test_value, sizeof(uint8_t));
    buffer.advance_write(sizeof(uint8_t));

    // Verify by reading
    uint8_t read_value = 0;
    buffer.read(&read_value);
    EXPECT_EQ(42, read_value);
}

TEST(StaticBuffer, PointerAfterWrite) {
    hexi::static_buffer<std::byte, 1024> buffer;
    std::vector<uint8_t> data = {10, 20, 30};
    buffer.write(data.data(), data.size());

    const std::byte* read_ptr = get_read_pointer(buffer);
    std::byte* write_ptr = get_write_pointer(buffer);

    EXPECT_NE(nullptr, read_ptr);
    EXPECT_NE(nullptr, write_ptr);
    EXPECT_EQ(10, static_cast<uint8_t>(read_ptr[0]));
}

