#include <gtest/gtest.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/buffer_read.h>
#include <vector>
#include <cstdint>

// Include the implementation
#include "implementation.hpp"

TEST(BufferAdaptor, FindByte) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    uint8_t data[] = {1, 2, 3, 4, 5};
    adaptor.write(data, sizeof(data));

    std::size_t pos = find_byte_in_buffer(adaptor, std::byte(3));

    EXPECT_EQ(2, pos);
}

TEST(BufferAdaptor, CheckContains) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    uint8_t data[] = {10, 20, 30, 40};
    adaptor.write(data, sizeof(data));

    EXPECT_TRUE(check_buffer_contains(adaptor, std::byte(20)));
    EXPECT_TRUE(check_buffer_contains(adaptor, std::byte(40)));
    EXPECT_FALSE(check_buffer_contains(adaptor, std::byte(99)));
}

TEST(BufferAdaptor, FindNotFound) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    uint8_t data[] = {1, 2, 3};
    adaptor.write(data, sizeof(data));

    std::size_t pos = find_byte_in_buffer(adaptor, std::byte(99));

    EXPECT_EQ(hexi::pmc::buffer_read::npos, pos);
}

