Looking at the code fragments, I can see that Hexi provides binary stream readers and writers for handling buffer operations. Here's the implementation for the varint encoding/decoding functions:

```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Handle unsigned integers
    if constexpr (std::is_unsigned_v<T>) {
        while (value > 0x7F) {
            // Write byte with continuation bit set
            uint8_t byte = static_cast<uint8_t>(value & 0x7F) | 0x80;
            writer.write(byte);
            bytes_written++;
            value >>= 7;
        }
        // Write final byte without continuation bit
        writer.write(static_cast<uint8_t>(value));
        bytes_written++;
    }
    // Handle signed integers using zigzag encoding
    else if constexpr (std::is_signed_v<T>) {
        // Convert to zigzag encoding: negative numbers become positive odd numbers,
        // positive numbers become positive even numbers
        typename std::make_unsigned_t<T> zigzag = 
            (static_cast<typename std::make_unsigned_t<T>>(value) << 1) ^ 
            (value >> (sizeof(T) * 8 - 1));

        // Encode as unsigned varint
        return encode_varint(writer, zigzag);
    }

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    T result = 0;
    int shift = 0;
    uint8_t byte;

    if constexpr (std::is_unsigned_v<T>) {
        do {
            byte = reader.read<uint8_t>();
            result |= static_cast<T>(byte & 0x7F) << shift;
            shift += 7;
        } while (byte & 0x80);
    }
    else if constexpr (std::is_signed_v<T>) {
        // Decode as unsigned first, then convert from zigzag
        auto zigzag = decode_varint<typename std::make_unsigned_t<T>>(reader);
        result = static_cast<T>((zigzag >> 1) ^ -(zigzag & 1));
    }

    return result;
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

