```cpp
#include <hexi/shared.h>
#include <cstring>
#include <cstddef>

using namespace hexi::detail;

bool check_regions_overlap(const void* src, std::size_t src_len, const void* dst, std::size_t dst_len) {
    if (!src || !dst || src_len == 0 || dst_len == 0) {
        return false;
    }

    const auto* src_start = static_cast<const char*>(src);
    const auto* src_end = src_start + src_len;
    const auto* dst_start = static_cast<const char*>(dst);
    const auto* dst_end = dst_start + dst_len;

    // Check if regions overlap by comparing their address ranges
    return (src_start < dst_end) && (dst_start < src_end);
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    if (!destination || !source || length == 0) {
        return false;
    }

    // Check for overlap first
    if (check_regions_overlap(source, length, destination, length)) {
        return false; // Overlapping regions, unsafe to copy
    }

    // Safe to copy
    std::memcpy(destination, source, length);
    return true;
}
```

The implementation:

1. **`check_regions_overlap`**: 
   - First checks for null pointers or zero-length regions
   - Converts the pointers to `char*` for proper pointer arithmetic
   - Checks if the regions overlap by comparing their start and end addresses
   - Returns `true` if they overlap, `false` otherwise

2. **`safe_memory_copy`**:
   - Validates input parameters
   - Calls `check_regions_overlap` to verify safety
   - Uses `std::memcpy` for the actual copy operation if safe
   - Returns `true` on success, `false` on failure (overlap or invalid parameters)

This follows safe memory practices by preventing overlapping memory copies which could lead to data corruption.

