    std::size_t read_size;
    std::size_t total_read;
    std::size_t read_limit;
    bool occurred;
};

ReadLimitInfo catch_stream_read_limit() {
    ReadLimitInfo info = {0, 0, 0, false};

    try {
        // Re-throw any currently caught exception to handle it
        throw;
    } catch (const hexi::stream_read_limit& e) {
        // Extract information from the stream_read_limit exception
        info.read_size = e.read_size;
        info.total_read = e.total_read;
        info.read_limit = e.read_limit;
        info.occurred = true;
    } catch (...) {
        // Catch any other exception but don't handle it
        info.occurred = false;
    }

    return info;
}

ReadLimitInfo safe_read_with_limit_check(hexi::pmc::binary_stream& stream, void* destination, std::size_t length) {
    ReadLimitInfo info = {0, 0, 0, false};

    try {
        // Attempt to read from the stream
        stream.read(destination, length);
        // If we get here, the read was successful
        info.occurred = false;
    } catch (const hexi::stream_read_limit& e) {
        // Catch the stream_read_limit exception and extract information
        info.read_size = e.read_size;
        info.total_read = e.total_read;
        info.read_limit = e.read_limit;
        info.occurred = true;
    }

    return info;
}
```

