#include <string>
#include <cstdint>
#include <vector>

struct PaddedData {
    uint16_t header;
    std::string data;
    uint32_t footer;
};

std::vector<uint8_t> serialize_with_padding(const PaddedData& packet) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Write header
    stream << packet.header;

    // Write data with length prefix (Hexi handles this automatically for std::string)
    stream << packet.data;

    // Write 16 bytes of padding filled with 0x00
    stream.fill<16>(0x00);

    // Write footer
    stream << packet.footer;

    return buffer;
}
```

