Looking at the code fragments, I can see that `hexi::pmc::buffer_base` is a base class that likely requires implementing several virtual methods from the buffer interfaces. Based on the fragments showing `buffer_read` and `buffer_write` classes, here's the complete implementation:

```cpp
#include <hexi/pmc/buffer_base.h>
#include <vector>
#include <cstddef>

class CustomBuffer : public hexi::pmc::buffer_base {
    std::vector<std::byte> data_;
    std::size_t read_pos_ = 0;
    std::size_t write_pos_ = 0;

public:
    // Required virtual methods from buffer_base/buffer_read
    std::size_t size() const override {
        return data_.size();
    }

    bool empty() const override {
        return data_.empty();
    }

    // buffer_read interface
    void read(void* destination, std::size_t length) override {
        if (read_pos_ + length > data_.size()) {
            // Handle read beyond buffer - you might want to throw an exception here
            return;
        }

        std::byte* dest_bytes = static_cast<std::byte*>(destination);
        std::copy(data_.begin() + read_pos_, data_.begin() + read_pos_ + length, dest_bytes);
        read_pos_ += length;
    }

    void copy(void* destination, std::size_t length) const override {
        if (read_pos_ + length > data_.size()) {
            // Handle copy beyond buffer
            return;
        }

        std::byte* dest_bytes = static_cast<std::byte*>(destination);
        std::copy(data_.begin() + read_pos_, data_.begin() + read_pos_ + length, dest_bytes);
        // Note: copy doesn't advance read position
    }

    void skip(std::size_t length) override {
        read_pos_ = std::min(read_pos_ + length, data_.size());
    }

    const std::byte& operator[](std::size_t index) const override {
        return data_.at(index);
    }

    std::size_t find_first_of(std::byte val) const override {
        for (std::size_t i = read_pos_; i < data_.size(); ++i) {
            if (data_[i] == val) {
                return i;
            }
        }
        return npos; // static_cast<std::size_t>(-1)
    }

    // buffer_write interface
    void write(const void* source, std::size_t length) override {
        const std::byte* src_bytes = static_cast<const std::byte*>(source);

        // If writing beyond current size, resize the vector
        if (write_pos_ + length > data_.size()) {
            data_.resize(write_pos_ + length);
        }

        std::copy(src_bytes, src_bytes + length, data_.begin() + write_pos_);
        write_pos_ += length;
    }

    void reserve(std::size_t length) override {
        data_.reserve(length);
    }

    bool can_write_seek() const override {
        return true;
    }

    void write_seek(hexi::pmc::buffer_seek direction, std::size_t offset) override {
        switch (direction) {
            case hexi::pmc::buffer_seek::begin:
                write_pos_ = std::min(offset, data_.size());
                break;
            case hexi::pmc::buffer_seek::current:
                write_pos_ = std::min(write_pos_ + offset, data_.size());
                break;
            case hexi::pmc::buffer_seek::end:
                write_pos_ = data_.size() >= offset ? data_.size() - offset : 0;
                break;
        }
    }

    // Additional methods for the combined buffer interface
    std::byte& operator[](std::size_t index) {
        return data_.at(index);
    }

    // Helper method to add data (for testing)
    void add_data(const void* source, std::size_t length) {
        const std::byte* bytes = static_cast<const std::byte*>(source);
        data_.insert(data_.end(), bytes, bytes + length);
        write_pos_ = data_.size(); // Update write position to end
    }

    // Helper method to clear data (for testing)
    void clear() {
        data_.clear();
        read_pos_ = 0;
        write_pos_ = 0;
    }

    // Helper methods to get/set positions
    std::size_t get_read_position() const { return read_pos_; }
    std::size_t get_write_position() const { return write_pos_; }
    void set_read_position(std::size_t pos) { read_pos_ = std::min(pos, data_.size()); }
    void set_write_position(std::size_t pos) { write_pos_ = std::min(pos, data_.size()); }

private:
    static constexpr std::size_t npos = static_cast<std::size_t>(-1);
};
