std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer to store the data
    std::vector<uint8_t> buffer;

    // Create a write adaptor for the buffer
    hexi::pmc::buffer_write_adaptor write_adaptor(buffer);

    // Check available space before writing
    if (write_adaptor.free() >= input_data.size()) {
        // Write the input data to the buffer
        write_adaptor.write(input_data.data(), input_data.size());
    }

    // Create a read adaptor for the same buffer
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer);

    // Check the readable size
    std::vector<uint8_t> result;
    if (read_adaptor.size() > 0) {
        result.resize(read_adaptor.size());
        // Read the data back from the buffer
        read_adaptor.read(result.data(), result.size());
    }

    return result;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create a read adaptor for the buffer data
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer_data);

    std::vector<uint8_t> result;

    // Get the actual peek size (minimum of requested size and available data)
    std::size_t actual_peek_size = std::min(peek_size, read_adaptor.size());

    if (actual_peek_size > 0) {
        // Method 1: Use copy() to peek without advancing read pointer
        result.resize(actual_peek_size);
        read_adaptor.copy(result.data(), actual_peek_size);

        // Method 2: Use read_ptr() to get pointer to current read position
        // const uint8_t* read_ptr = read_adaptor.read_ptr();
        // result.assign(read_ptr, read_ptr + actual_peek_size);

        // Now actually consume the data by reading it (advancing the pointer)
        std::vector<uint8_t> consumed_data(actual_peek_size);
        read_adaptor.read(consumed_data.data(), actual_peek_size);
    }

    return result;
}
