```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a write adaptor with an underlying vector
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_write_adaptor adaptor(buffer);

    std::size_t total_written = 0;

    for (const auto& chunk : chunks) {
        // Check available space before each write
        std::size_t free_space = adaptor.free();

        // Write the chunk data
        adaptor.write(chunk.data(), chunk.size());
        total_written += chunk.size();
    }

    return total_written;
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create a read adaptor from the input buffer
    hexi::pmc::buffer_read_adaptor adaptor(const_cast<std::vector<uint8_t>&>(buffer));

    std::vector<uint8_t> result;

    // Read until buffer is empty
    while (adaptor.size() > 0) {
        // Determine how much to read in this chunk
        std::size_t bytes_to_read = std::min(chunk_size, adaptor.size());

        // Create temporary buffer for reading
        std::vector<uint8_t> temp_chunk(bytes_to_read);

        // Read the data
        adaptor.read(temp_chunk.data(), bytes_to_read);

        // Append to result
        result.insert(result.end(), temp_chunk.begin(), temp_chunk.end());

        // Check remaining data after read
        std::size_t remaining = adaptor.size();
    }

    return result;
}
```

Key points about this implementation:

1. **write_multiple_chunks**:
   - Uses `buffer_write_adaptor` to write data in chunks
   - Calls `free()` before each write to check available space
   - Tracks total bytes written across all chunks

2. **read_partial_data**:
   - Uses `buffer_read_adaptor` to read data partially
   - Reads in chunks of specified size using `size()` to check remaining data
   - Continues reading until the buffer is completely consumed
   - Returns all read data concatenated together

The adaptors handle the buffer management internally, and we use the Hexi PMC interface as shown in the test fragments to properly interact with the buffer state.

