struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Create a buffer adaptor from the input buffer
    hexi::pmc::buffer_adaptor adaptor(buffer);

    Header header;
    // Use copy() to peek at header data without advancing read cursor
    adaptor.copy(&header, sizeof(header));

    // Use read_ptr() to verify pointer position (cursor should not have moved)
    const std::byte* ptr = adaptor.read_ptr();
    // Verify we're still at the beginning of the buffer
    if (ptr != reinterpret_cast<const std::byte*>(buffer.data())) {
        // Handle error - read cursor should not have advanced
        throw std::runtime_error("Read cursor advanced unexpectedly");
    }

    return header;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    // Create a buffer adaptor from the input buffer
    hexi::pmc::buffer_adaptor adaptor(buffer);

    uint8_t first_byte;
    // Use copy() to peek at first byte without consuming it
    adaptor.copy(&first_byte, sizeof(first_byte));

    std::vector<uint8_t> result;

    // Condition: if first byte is 0x01, read the entire buffer
    if (first_byte == 0x01) {
        // Resize result to hold all available data
        result.resize(adaptor.size());

        // Use read() to consume the data
        adaptor.read(result.data(), result.size());
    }
    // Alternative condition: if first byte indicates a specific size
    else if (first_byte == 0x02) {
        // Peek at the next byte to determine how much data to read
        uint8_t size_byte;
        adaptor.copy(&size_byte, sizeof(size_byte));

        // Read the determined amount of data
        result.resize(size_byte);
        adaptor.read(result.data(), result.size());
    }

    return result;
}
