#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <bit>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialize sensor_id (no conversion needed for uint32_t)
        adaptor(sensor_id);

        // Serialize temperatures array size
        uint32_t size = static_cast<uint32_t>(temperatures.size());
        adaptor(size);

        // Serialize each temperature with endianness conversion
        for (const auto& temp : temperatures) {
            // Convert from native to little-endian
            float temp_le = hexi::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor(temp_le);
        }

        // Serialize pressure with endianness conversion
        double pressure_le = hexi::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor(pressure_le);
    }

    void serialise(auto& adaptor) {
        // Deserialize sensor_id
        adaptor(sensor_id);

        // Deserialize temperatures array size
        uint32_t size;
        adaptor(size);

        // Resize and deserialize temperatures with endianness conversion
        temperatures.resize(size);
        for (auto& temp : temperatures) {
            adaptor(temp);
            // Convert from little-endian to native in-place
            hexi::little_to_native_inplace(temp);
        }

        // Deserialize pressure with endianness conversion
        adaptor(pressure);
        hexi::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use stream's serialise method
    stream.serialise(data);

    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    MeasurementData data;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use stream's deserialise method
    stream.deserialise(data);

    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    SensorInfo info;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use view to extract null-terminated sensor name if present
    info.sensor_name = stream.view();

    // Enforce read bounds before reading sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    stream.get(info.sensor_id);

    // Skip remaining data
    stream.skip(adaptor.size() - adaptor.tell());

    return info;
}
